import os
import logging

# Set up logging
logging.basicConfig(filename='file_deletion.log', level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

def log_error(error):
    """Custom error handler to log exceptions."""
    logging.error(error)

def delete_files_and_directories(directory, extension):
    """Recursively deletes files with the specified extension and empty directories."""
    try:
        for item in os.listdir(directory):
            item_path = os.path.join(directory, item)
            if os.path.isfile(item_path):
                if item.endswith(extension):
                    os.remove(item_path)
                    logging.info(f"Deleted file: {item_path}")
            elif os.path.isdir(item_path):
                delete_files_and_directories(item_path, extension)
    except Exception as e:
        log_error(f"Error deleting files/directories: {e}")

def main():
    user_directory = '/home/user/'
    extension = '.tmp'
    delete_files_and_directories(user_directory, extension)

if __name__ == "__main__":
    main()
